def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    H = int(data[0])
    W = int(data[1])
    grid = data[2:2+H]

    # Convert each row to a list of integers
    grid = [list(map(int, list(row))) for row in grid]

    # Since W is small (<= 18), we can try all possible combinations of flipping columns
    min_sum = float('inf')

    # Precompute the sum for each row with and without flipping
    row_sums = []
    for row in grid:
        row_sum = sum(row)
        row_sums.append((row_sum, W - row_sum))

    for mask in range(1 << W):
        # Calculate the sum for each row after column flips
        current_total = 0
        for j in range(W):
            if (mask >> j) & 1:
                # Column j is flipped; invert the contribution of this column
                for i in range(H):
                    current_total += 1 - grid[i][j]
            else:
                # Column j is not flipped; use original values
                for i in range(H):
                    current_total += grid[i][j]

        # Optimize by flipping rows to minimize total sum
        for i in range(H):
            ones, zeros = row_sums[i]
            if ones > zeros:
                current_total += (ones - zeros)

        if current_total < min_sum:
            min_sum = current_total

    print(min_sum)

if __name__ == "__main__":
    main()
